raw_commands:
{% set all_labels = [] %}
{% for row in doc.item_table %}
    {% for i in range(row.barcode_qty) %}
        {% set _ = all_labels.append(row.items) %}
    {% endfor %}
{% endfor %}

{% for i in range(0, all_labels|length, 2) %}
{% set left_item = frappe.get_doc('Item', all_labels[i]) %}
{% set right_item = None %}
{% if i+1 < all_labels|length %}
    {% set right_item = frappe.get_doc('Item', all_labels[i+1]) %}
{% endif %}

SIZE 76 mm,25 mm
GAP 2 mm,0
DIRECTION 1
CLS

REM --- Left label (0,0 origin) ---
TEXT 20,15,"2",0,1,1,"E MART KITCHEN CARE"
TEXT 20,40,"2",0,1,1,"{{ left_item.item_name }}"
BARCODE 20,65,"128",40,1,0,2,2,"{{ left_item.barcodes[0].barcode }}"
TEXT 20,140,"1",0,1,1,"MRP: Rs {{ left_item.mrp or '' }}"
TEXT 20,160,"2",0,1,1,"ERP: Rs {{ left_item.erp or '' }}"
TEXT 20,185,"1",0,1,1,"(INCL. ALL TAXES)"

{% if right_item %}
REM --- Right label (shifted ≈ 380 dots to align better) ---
TEXT 320,15,"2",0,1,1,"E MART KITCHEN CARE"
TEXT 320,40,"2",0,1,1,"{{ right_item.item_name }}"
BARCODE 320,65,"128",40,1,0,2,2,"{{ right_item.barcodes[0].barcode }}"
TEXT 320,140,"1",0,1,1,"MRP: Rs {{ right_item.mrp or '' }}"
TEXT 320,160,"2",0,1,1,"ERP: Rs {{ right_item.erp or '' }}"
TEXT 320,185,"1",0,1,1,"(INCL. ALL TAXES)"
{% endif %}

PRINT 1
{% endfor %}
